"<?php\n\n/**\n * Database Setup Script for Dayana Enterprises ERP\n * Run: php db_setup.php\n */\n\necho \"\\n========================================\\n\";\necho \" Dayana Enterprises ERP - Database Setup\\n\";\necho \"========================================\\n\\n\";\n\n// Step 1: Check .env file\n$envFile = __DIR__ . '/.env';\nif (!file_exists($envFile)) {\n    die(\"ERROR: .env file not found! Run: cp .env.example .env\\n\");\n}\necho \"[✓] .env file found\\n\";\n\n// Read DB config from .env\n$env = parse_ini_file($envFile);\n$dbName = $env['DB_DATABASE'] ?? 'dayana_erp';\n$dbUser = $env['DB_USERNAME'] ?? 'root';\n$dbPass = $env['DB_PASSWORD'] ?? '';\n$dbHost = $env['DB_HOST'] ?? '127.0.0.1';\n\necho \"[•] Database: $dbName\\n\";\necho \"[•] Host: $dbHost\\n\";\necho \"[•] User: $dbUser\\n\\n\";\n\n// Step 2: Create database\necho \"[1/6] Creating database...\\n\";\n$cmd = sprintf('mysql -u%s -p\'%s\' -h%s -e \"CREATE DATABASE IF NOT EXISTS %s CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;\" 2>&1',\n    escapeshellarg($dbUser),\n    str_replace('!', '\\\\!', $dbPass),\n    escapeshellarg($dbHost),\n    escapeshellarg($dbName)\n);\n$output = shell_exec($cmd);\necho $output ? \"  Output: $output\" : '';\necho \"[✓] Database ready\\n\\n\";\n\n// Step 3: Clear cache\necho \"[2/6] Clearing cache...\\n\";\necho shell_exec('php artisan config:clear 2>&1');\necho shell_exec('php artisan optimize:clear 2>&1');\necho \"[✓] Cache cleared\\n\\n\";\n\n// Step 4: Run migrations\necho \"[3/6] Running migrations...\\n\";\n$output = shell_exec('php artisan migrate --force 2>&1');\necho $output;\necho \"[✓] Migrations complete\\n\\n\";\n\n// Step 5: Seed database\necho \"[4/6] Seeding roles & permissions...\\n\";\n$output = shell_exec('php artisan db:seed --class=RolePermissionSeeder --force 2>&1');\necho $output ? \"$output\\n\" : '';\necho \"[✓] Roles seeded\\n\\n\";\n\necho \"[5/6] Seeding users...\\n\";\n$output = shell_exec('php artisan db:seed --class=UserSeeder --force 2>&1');\necho $output ? \"$output\\n\" : '';\necho \"[✓] Users seeded\\n\\n\";\n\necho \"[6/6] Seeding master data...\\n\";\n$output = shell_exec('php artisan db:seed --class=DatabaseSeeder --force 2>&1');\necho $output ? \"$output\\n\" : '';\necho \"[✓] Master data seeded\\n\\n\";\n\n// Summary\necho \"========================================\\n\";\necho \" SETUP COMPLETE!\\n\";\necho \"========================================\\n\\n\";\necho \"Login Credentials:\\n\";\necho \"  Super Admin: admin@dayana.com / password\\n\";\necho \"  Manager:     manager@dayana.com / password\\n\";\necho \"  Cashier:     cashier@dayana.com / password\\n\";\necho \"  Store Keeper: store@dayana.com / password\\n\";\necho \"  Accountant:  accountant@dayana.com / password\\n\\n\";\necho \"Access: http://178.238.236.42/\\n\";\necho \"========================================\\n\";"